#!/usr/bin/env node
// One-shot screenshot capture for the OSINT toolkit README. Run against
// a live compose stack after ./scripts/seed-demo.sh has staged the demo
// target. Writes PNGs directly into ../../docs/screenshots/ at the
// 1440x900 viewport documented in docs/regenerating-screenshots.md.
//
//   node e2e/scripts/capture-osint-screenshots.mjs
//
// The script is deliberately not a @playwright/test file so it doesn't
// pollute the CI smoke suite - screenshots should be regenerated by a
// maintainer on demand, not on every push.

import { chromium } from "@playwright/test";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const OUT_DIR = resolve(__dirname, "../../docs/screenshots");
const BASE_URL = process.env.OSINT_BASE_URL ?? "http://localhost:3001";

const shots = [
  { route: "/", file: "osint-01-dashboard.png" },
  { route: "/targets/1", file: "osint-02-target-detail.png" },
  { route: "/investigate", file: "osint-03-investigate.png" },
];

const browser = await chromium.launch();
const ctx = await browser.newContext({
  viewport: { width: 1440, height: 900 },
  colorScheme: "dark",
});
const page = await ctx.newPage();

for (const { route, file } of shots) {
  const url = `${BASE_URL}${route}`;
  console.log(`capturing ${url} → ${file}`);
  await page.goto(url, { waitUntil: "networkidle" });
  // Small settle so any transition/fade completes before the shot.
  await page.waitForTimeout(500);
  await page.screenshot({ path: `${OUT_DIR}/${file}`, fullPage: false });
}

await ctx.close();
await browser.close();
console.log(`done - wrote ${shots.length} files to ${OUT_DIR}`);
